import React, { useEffect, useRef, useState, useCallback } from 'react'
import { API_BASE } from '../lib/apiBase'

// =============================================
// Starfield Background (Canvas 2D)
// =============================================
function Starfield() {
  const canvasRef = useRef(null)
    useEffect(() => {
        const c = canvasRef.current
            if (!c) return
                const ctx = c.getContext('2d')
                    const DPR = Math.min(window.devicePixelRatio || 1, 2)
                        function resize() {
                              c.width = Math.round(innerWidth * DPR)
                                    c.height = Math.round(innerHeight * DPR)
                                          ctx.setTransform(DPR, 0, 0, DPR, 0, 0)
                                              }
                                                  resize()
                                                      const stars = []
                                                          for (let i = 0; i < 2200; i++) {
                                                                stars.push({
                                                                        x: Math.random() * 9999, y: Math.random() * 9999,
                                                                                r: Math.random() * 0.85 + 0.1, a: Math.random() * 0.55 + 0.08,
                                                                                        fp: Math.random() * 6.283, fs: Math.random() * 1.4 + 0.3
                                                                                              })
                                                                                                  }
                                                                                                      let interval
                                                                                                          function draw() {
                                                                                                                const now = Date.now() * 0.001
                                                                                                                      ctx.fillStyle = '#04060f'
                                                                                                                            ctx.fillRect(0, 0, innerWidth, innerHeight)
                                                                                                                                  for (const s of stars) {
                                                                                                                                          ctx.globalAlpha = s.a * (0.5 + 0.5 * Math.sin(now * s.fs + s.fp))
                                                                                                                                                  ctx.fillStyle = '#aac8ff'
                                                                                                                                                          ctx.beginPath()
                                                                                                                                                                  ctx.arc(s.x % innerWidth, s.y % innerHeight, s.r, 0, 6.283)
                                                                                                                                                                          ctx.fill()
                                                                                                                                                                                }
                                                                                                                                                                                      ctx.globalAlpha = 1
                                                                                                                                                                                          }
                                                                                                                                                                                              draw()
                                                                                                                                                                                                  interval = setInterval(draw, 80)
                                                                                                                                                                                                      const onResize = () => { resize(); draw() }
                                                                                                                                                                                                          window.addEventListener('resize', onResize)
                                                                                                                                                                                                              return () => { clearInterval(interval); window.removeEventListener('resize', onResize) }
                                                                                                                                                                                                                }, [])
                                                                                                                                                                                                                  return <canvas ref={canvasRef} className="cs-bg-canvas" />
                                                                                                                                                                                                                  }

                                                                                                                                                                                                                  // =============================================
